import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const LeagueGeneration = () => {
    const [clasificacion, setClasificacion] = useState([]);
    const [calendario, setCalendario] = useState([]);
    const navigate = useNavigate();

    useEffect(() => {
        fetch("/data/equipos.json")
            .then((response) => response.json())
            .then((data) => {
                const equipos = data.filter((equipo) => equipo.player);
                setClasificacion(equipos.map((equipo) => ({ ...equipo, puntos: 0 })));
                setCalendario(generarCalendario(equipos));
            })
            .catch((error) => console.error("Error al cargar los equipos:", error));
    })
};

export default LeagueGeneration;
